#!/usr/bin/env bash
# SWE-rebench-style eval (auto-generated by build_swerebench_configs.py).
# Reads tests/install_config.json, runs the test_cmd, parses stdout via the
# named log_parser (vendored from SWE-rebench-V2 — copied into this tests/
# dir at scaffold time), scores by FAIL_TO_PASS pass rate.
#
# Harbor mounts the entire tests/ directory at /tests in the sandbox, so
# log_parsers.py and swe_constants.py live alongside this script.
set +e

# E2B's commands.run(envs=None) strips Dockerfile ENV PATH — hardcode every install location
export PATH="/usr/local/go/bin:/root/go/bin:/home/agent/go/bin:/usr/local/cargo/bin:/opt/cargo/bin:/root/.cargo/bin:/home/agent/.cargo/bin:/venv/bin:/opt/venv/bin:/usr/local/bin:/root/.bun/bin:/home/agent/.bun/bin:/usr/bin:/bin:${PATH}"

TASK_DIR="${TASK_DIR:-$(cd "$(dirname "$0")/.." && pwd)}"
LOGS_DIR="${LOGS_DIR:-/logs/verifier}"
EVAL_DIR="${EVAL_DIR:-/tests}"
mkdir -p "$LOGS_DIR"

CONFIG="$TASK_DIR/tests/install_config.json"
if [ ! -f "$CONFIG" ]; then
    echo "ERROR: missing $CONFIG" >&2
    echo 0.0 > "$LOGS_DIR/reward.txt"
    exit 1
fi
if [ ! -f "$EVAL_DIR/log_parsers.py" ]; then
    echo "ERROR: log_parsers not mounted at $EVAL_DIR — orchestrator must mount data-pipeline/scaffold/log_parsers/ here" >&2
    echo 0.0 > "$LOGS_DIR/reward.txt"
    exit 1
fi

REPO_DIR=$(python3 -c "import json; print(json.load(open('$CONFIG'))['repo_dir'])")
TEST_CMD=$(python3 -c "import json; print(json.load(open('$CONFIG'))['test_cmd'])")

cd "$REPO_DIR" || { echo "ERROR: cd $REPO_DIR" >&2; echo 0.0 > "$LOGS_DIR/reward.txt"; exit 1; }

LOG="$LOGS_DIR/test_run.log"
echo "[eval] running: $TEST_CMD" | tee -a "$LOG"
eval "$TEST_CMD" 2>&1 | tee -a "$LOG"

python3 - "$CONFIG" "$LOG" "$LOGS_DIR/reward.txt" "$EVAL_DIR" <<'PYEOF'
import json, sys
cfg_path, log_path, reward_path, eval_dir = sys.argv[1], sys.argv[2], sys.argv[3], sys.argv[4]
sys.path.insert(0, eval_dir)
from log_parsers import NAME_TO_PARSER

cfg = json.load(open(cfg_path))
import re as _re
_ansi_re = _re.compile(r"\x1b\[[0-9;]*[mGKHfABCDsuJ]")
log = _ansi_re.sub("", open(log_path).read())

parser = NAME_TO_PARSER.get(cfg["log_parser"])
if parser is None:
    print(f"[eval] ERROR: unknown log_parser {cfg['log_parser']!r}")
    open(reward_path, "w").write("0.0\n")
    sys.exit(0)

parsed = parser(log)  # {test_name: status}
fail_to_pass = cfg.get("FAIL_TO_PASS", [])
pass_to_pass = cfg.get("PASS_TO_PASS", [])

if not fail_to_pass:
    print("[eval] no FAIL_TO_PASS — falling back to overall pass rate")
    total = len(parsed)
    if total == 0:
        reward = 0.0
    else:
        passed = sum(1 for v in parsed.values() if v == "PASSED")
        reward = passed / total
else:
    f2p_pass = sum(1 for t in fail_to_pass if parsed.get(t) == "PASSED")
    reward = f2p_pass / max(1, len(fail_to_pass))
    if pass_to_pass:
        p2p_fail = sum(1 for t in pass_to_pass if parsed.get(t) and parsed[t] != "PASSED")
        if p2p_fail > 0:
            print(f"[eval] {p2p_fail} P2P regression(s) — zeroing reward")
            reward = 0.0

reward = max(0.0, min(1.0, reward))
open(reward_path, "w").write(f"{reward:.6f}\n")
print(f"[eval] reward={reward:.4f}  parser={cfg['log_parser']}  "
      f"FAIL_TO_PASS: {sum(1 for t in fail_to_pass if parsed.get(t) == 'PASSED')}/{len(fail_to_pass)}")
PYEOF

cat "$LOGS_DIR/reward.txt"

# >>> auto_gate_bridge >>>
# Auto-generated by scripts/fix_emit_gates.py.
# Bridges manifest gates → /logs/verifier/gates.json so the canonical
# F2P-coverage formula matches the legacy reward.txt for tasks that were
# scored only via inline `add_reward` style. Idempotent.
#
# Semantics:
#   F2P gate without an explicit emit → proportionally pass `round(N*L)`
#     gates (where N = total F2P gates, L = legacy reward.txt), so the
#     canonical f2p_pass_rate reproduces the legacy reward.
#   P2P_REGRESSION without an explicit emit → passed: true (informational,
#     matches pre-canonical bash where unemitted P2P had no effect).
#
# After bridging, reward.txt is left as the legacy value. The host-side
# canonicalize_reward_from_gates() (per_turn_replay.py, oracle_replay.py)
# reads the now-complete gates.json and recomputes via the unified formula.
python3 - <<'AUTO_GATE_BRIDGE_PYEOF'
import json, os, sys
from pathlib import Path

LOGS = Path("/logs/verifier")
gates_path = LOGS / "gates.json"
reward_path = LOGS / "reward.txt"

# Locate the manifest at runtime. Harbor mounts the harbor task's tests/
# dir at /tests so the manifest is /tests/test_manifest.yaml.
manifest_candidates = [
    Path("/tests/test_manifest.yaml"),
    Path(os.environ.get("TEST_MANIFEST", "")),
]
manifest_path = next((p for p in manifest_candidates if p and p.is_file()), None)
if manifest_path is None:
    sys.exit(0)

try:
    import yaml
    raw = yaml.safe_load(manifest_path.read_text())
except Exception:
    sys.exit(0)

gates = (raw or {}).get("gates") or []
if not gates:
    sys.exit(0)

try:
    legacy_reward = float(reward_path.read_text().strip())
except Exception:
    legacy_reward = 0.0

existing_ids = set()
try:
    txt = gates_path.read_text().strip()
    if txt.startswith("[") or txt.startswith("{"):
        d = json.loads(txt)
        if isinstance(d, dict) and "gates" in d:
            for g in d["gates"]:
                if isinstance(g, dict) and g.get("id"):
                    existing_ids.add(g["id"])
        elif isinstance(d, list):
            for g in d:
                if isinstance(g, dict) and g.get("id"):
                    existing_ids.add(g["id"])
    else:
        for line in txt.splitlines():
            line = line.strip()
            if not line:
                continue
            try:
                obj = json.loads(line)
                if obj.get("id"):
                    existing_ids.add(obj["id"])
            except Exception:
                pass
except FileNotFoundError:
    pass

all_gate_ids = []
f2p_missing_ids = []
p2p_missing_ids = []
for g in gates:
    if not isinstance(g, dict):
        continue
    gid = g.get("id")
    kind = g.get("kind", "F2P")
    if not gid:
        continue
    all_gate_ids.append((gid, kind))
    if gid in existing_ids:
        continue
    if kind == "F2P":
        f2p_missing_ids.append(gid)
    elif kind.startswith("P2P"):  # P2P_REGRESSION, P2P, deprecated kinds
        p2p_missing_ids.append(gid)

f2p_total = sum(1 for gid, kind in all_gate_ids if kind == "F2P")
target_passes = int(round(legacy_reward * f2p_total))

explicit_pass = 0
try:
    with gates_path.open() as _f:
        for line in _f:
            try:
                d = json.loads(line)
            except Exception:
                continue
            if d.get("id") and d.get("passed"):
                for (gid, kind) in all_gate_ids:
                    if gid == d["id"] and kind == "F2P":
                        explicit_pass += 1
                        break
except Exception:
    pass

bridge_passes = max(0, target_passes - explicit_pass)
bridge_passes = min(bridge_passes, len(f2p_missing_ids))

to_append = []
for i, gid in enumerate(f2p_missing_ids):
    passed = bool(i < bridge_passes)
    detail = "auto-bridge: F2P proportional (target=%d/%d, legacy=%.3f)" % (
        target_passes, f2p_total, legacy_reward,
    )
    to_append.append({"id": gid, "passed": passed, "detail": detail})
for gid in p2p_missing_ids:
    to_append.append({
        "id": gid,
        "passed": True,
        "detail": "auto-bridge: P2P default-pass (no explicit emit)",
    })

if to_append:
    LOGS.mkdir(parents=True, exist_ok=True)
    with gates_path.open("a") as _f:
        for obj in to_append:
            _f.write(json.dumps(obj) + "\n")
AUTO_GATE_BRIDGE_PYEOF
# <<< auto_gate_bridge <<<
